noncompliant:
// Noncompliant: Function that never returns but not marked as noreturn
void exitProgram(int code) {
  printf("Exiting with code %d\n", code);
  exit(code);  // This function never returns
}

compliant:
// Compliant: Function properly marked with noreturn attribute
__attribute__((noreturn)) void exitProgram(int code) {
  printf("Exiting with code %d\n", code);
  exit(code);
}

// Alternative syntax for C11
_Noreturn void fatalError(const char* msg) {
  fprintf(stderr, "Fatal error: %s\n", msg);
  abort();
}
